__device__ __forceinline__ void BuildDP(const TKparams& Kparams, int kang_ind, u64* d, u32 flags)
{
	int ind = atomicAdd(Kparams.DPTable + kang_ind, 0x10000);
	ind >>= 16;
	if (ind >= DPTABLE_MAX_CNT)
		return;
	// Requirements 3.2: Read full 256-bit x-coordinate (8 x u32 per entry)
	int4* rx_ptr = (int4*)(Kparams.DPTable + Kparams.KangCnt + (kang_ind * DPTABLE_MAX_CNT + ind) * 8);
	int4 rx0 = rx_ptr[0];  // x[0], x[1]
	int4 rx1 = rx_ptr[1];  // x[2], x[3]

	// Reserve an output slot with saturation to avoid corrupting the header counter.
	// Header layout in DPs_out:
	//   [0] = count
	//   [1] = overflow flag (set to 1 if drops occur)
	//   [2] = DPTable overflow flag (set to 1 if per-kang DPTable saturates)
	//   [3] = reserved
	u32 pos;
	while (true) {
		pos = *Kparams.DPs_out;
		if (pos >= Kparams.MaxDPCnt) {
			atomicExch(Kparams.DPs_out + 1, 1);
			return;
		}
		if (atomicCAS(Kparams.DPs_out, pos, pos + 1) == pos) {
			break;
		}
	}
	// Requirements 3.2, 3.5: Store full 256-bit x-coordinate in DPs_out
	// New layout (GPU_DP_SIZE = 64 bytes):
	//   DPs[0-7]:  x[0-3] (32 bytes, full 256-bit x-coordinate)
	//   DPs[8-13]: d[0-2] (24 bytes, 192-bit distance/wlog)
	//   DPs[14]:   kang type (4 bytes)
	//   DPs[15]:   padding (4 bytes)
	u32* DPs = Kparams.DPs_out + 4 + pos * GPU_DP_SIZE / 4;
	*(int4*)&DPs[0] = rx0;   // x[0], x[1]
	*(int4*)&DPs[4] = rx1;   // x[2], x[3]
	*(int4*)&DPs[8] = ((int4*)d)[0];  // d[0], d[1]
	*(u64*)&DPs[12] = d[2];  // d[2]
	DPs[14] = 3 * kang_ind / Kparams.KangCnt; //kang type
	DPs[15] = flags;
}

