static int CompareHashedPTableEntryByHash(const void* a, const void* b)
{
	const HashedPTableEntry* ea = (const HashedPTableEntry*)a;
	const HashedPTableEntry* eb = (const HashedPTableEntry*)b;
	if (ea->hash < eb->hash) return -1;
	if (ea->hash > eb->hash) return 1;
	return memcmp(ea->d, eb->d, sizeof(ea->d));
}

int RCGpuKang::CalcKangCnt()
{
	Kparams.BlockCnt = mpCnt;
	Kparams.BlockSize = IsOldGpu ? 512 : 256;
	Kparams.GroupCnt = IsOldGpu ? 64 : 24;
	return Kparams.BlockSize* Kparams.GroupCnt* Kparams.BlockCnt;
}

