void RCGpuKang::GenerateRndDistances_BernsteinLange()
{
	// Bernstein-Lange recommends x ∈ [0, ℓ/256] = [0, 2^(Range-8))
	// But we need some spread to avoid all kangaroos starting too close
	// Use Range - 8 bits for the random offset
	int x_bits = Range - 8;
	if (x_bits < 8) x_bits = 8;  // Minimum 8 bits for some randomness
	if (x_bits > Range - 4) x_bits = Range - 4;  // Maximum Range-4 bits

	for (int i = 0; i < KangCnt; i++)
	{
		EcInt d;
		d.RndBits(x_bits);
		d.data[0] &= 0xFFFFFFFFFFFFFFFE;  // Must be even for point addition
		memcpy(RndPnts[i].priv, d.data, 24);
	}
}

