				//   jmp_x, jmp_y = jump point Q

				// === Compute P+Q first (standard) ===
				SubModP(x, tmp2, jmp_x);   // x = λ² - jmp_x
				SubModP(x, x, x0);          // x = x_{P+Q}
				SubModP(y, x0, x);          // y = x0 - x_{P+Q}
				MulModP(y, y, tmp);         // y = (x0 - x_{P+Q}) * λ
				SubModP(y, y, y0);          // y = y_{P+Q}

