DPBufferManager::DPBufferManager()
    : m_capacity(0)
    , m_used(0)
    , m_initialized(false)
    , m_warning_logged(false)
{
}

DPBufferManager::~DPBufferManager()
{
    Release();
}

u32 DPBufferManager::ComputeOptimalSize(u32 gpu_count, u32 dp_bits, u32 step_cnt, u32 kang_per_gpu)
{
    // Validate inputs
    if (gpu_count == 0) {
        return MIN_BUFFER_SIZE;
    }
    if (dp_bits < MIN_DP_BITS || dp_bits > MAX_DP_BITS) {
        printf("WARNING: dp_bits (%u) out of range [%d, %d], using default buffer size\n",
               dp_bits, MIN_DP_BITS, MAX_DP_BITS);
        return MIN_BUFFER_SIZE;
    }
    if (step_cnt == 0) {
        step_cnt = STEP_CNT;  // Use default from defs.h
    }

    // Calculate expected DPs per kernel iteration
    // Formula: expected_dps = total_kangs * step_cnt / 2^dp_bits
    //
    // For each kangaroo, after step_cnt steps, the probability of hitting
    // a distinguished point is step_cnt / 2^dp_bits
    //
    // Total kangaroos = gpu_count * kang_per_gpu (or estimate if not provided)
    u64 total_kangs;
    if (kang_per_gpu > 0) {
        total_kangs = (u64)gpu_count * kang_per_gpu;
    } else {
        // Estimate based on typical GPU configuration
        // Old GPU: ~2.2M kangaroos, New GPU: ~1.5M kangaroos
        // Use conservative estimate of 2M per GPU
        total_kangs = (u64)gpu_count * 2000000;
    }

    // Expected DPs per iteration
    // Use u64 arithmetic to prevent overflow
    u64 dp_divisor = 1ULL << dp_bits;
    u64 expected_dps_per_iter = (total_kangs * step_cnt) / dp_divisor;

    // Apply safety factor for variance (DPs follow Poisson distribution)
    // We want buffer to handle multiple iterations without overflow
    u64 buffer_size = (u64)(expected_dps_per_iter * SAFETY_FACTOR);

    // Clamp to valid range
    if (buffer_size < MIN_BUFFER_SIZE) {
        buffer_size = MIN_BUFFER_SIZE;
    }
    if (buffer_size > MAX_BUFFER_SIZE) {
        buffer_size = MAX_BUFFER_SIZE;
    }

    return (u32)buffer_size;
}

bool DPBufferManager::Initialize(u32 buffer_capacity)
{
    // Release any existing resources
    Release();

    // Validate capacity
    if (buffer_capacity == 0) {
        printf("ERROR: DPBufferManager::Initialize - buffer_capacity cannot be 0\n");
        return false;
    }

    // Clamp to valid range
    if (buffer_capacity < MIN_BUFFER_SIZE) {
        printf("WARNING: Requested buffer capacity (%u) below minimum, using %u\n",
               buffer_capacity, MIN_BUFFER_SIZE);
        buffer_capacity = MIN_BUFFER_SIZE;
    }
    if (buffer_capacity > MAX_BUFFER_SIZE) {
        printf("WARNING: Requested buffer capacity (%u) above maximum, using %u\n",
               buffer_capacity, MAX_BUFFER_SIZE);
        buffer_capacity = MAX_BUFFER_SIZE;
    }

    m_capacity = buffer_capacity;
    m_used = 0;
    m_warning_logged = false;
    m_initialized = true;

    printf("DPBufferManager initialized: capacity=%u entries (%.2f MB at %d bytes/entry)\n",
           m_capacity, (float)(m_capacity * GPU_DP_SIZE) / (1024 * 1024), GPU_DP_SIZE);

    return true;
}

