	// Example: dp_bits=21 -> mask=0xFFFFF80000000000 (high 21 bits set)
	// Example: dp_bits=32 -> mask=0xFFFFFFFF00000000 (high 32 bits set)
	// Example: dp_bits=60 -> mask=0xFFFFFFFFFFFFFFF0 (high 60 bits set)
	// IMPORTANT: Using 1ULL ensures u64 arithmetic, avoiding undefined behavior
	// when (64 - dp_bits) >= 32 (which would cause issues with 32-bit shift)
	if (DP < MIN_DP_BITS || DP > MAX_DP_BITS) {
		printf("GPU %d: DP bits %d out of valid range [%d, %d]\n", CudaIndex, DP, MIN_DP_BITS, MAX_DP_BITS);
