#if __CUDA_ARCH__ < 890
#define OLD_GPU
#endif
#ifdef OLD_GPU
#define BLOCK_SIZE			BLOCK_SIZE_OLD_GPU		
#define PNT_GROUP_CNT		PNT_GROUP_OLD_GPU	
#else
#define BLOCK_SIZE			BLOCK_SIZE_NEW_GPU	
#define PNT_GROUP_CNT		PNT_GROUP_NEW_GPU
#endif
#else //CPU, fake values
#define BLOCK_SIZE			BLOCK_SIZE_OLD_GPU
#define PNT_GROUP_CNT		PNT_GROUP_OLD_GPU
#endif

// kang type
#define TAME				0  // Tame kangs
#define WILD1				1  // Wild kangs1 
#define WILD2				2  // Wild kangs2

//==============================================================================
// Unified DP Detection Constants
// Requirements: 3.1, 3.2 - Unified DP detection across TableGenKernel and KernelA
//==============================================================================

// DP_LIMB_INDEX: Which limb of x-coordinate to use for DP detection
// Value 3 means x[3] (high 64 bits of 256-bit x-coordinate)
// This MUST match KernelA's DP detection: (x[3] & dp_mask64) == 0
// Requirements: 3.1
#define DP_LIMB_INDEX		3

// GPU_DP_SIZE: Size of DP entry in bytes for GPU output buffer
// Updated from 48 to 64 to store full 256-bit x-coordinate (4 x u64 = 32 bytes)
// plus wlog (24 bytes) + type (1 byte) + padding (7 bytes) = 64 bytes
// Requirements: 3.2 - Store full 256-bit x-coordinate for reliable matching
#define GPU_DP_SIZE			64

// Minimum and maximum DP bits supported
// DP bits control the sparsity of distinguished points: probability = 1/2^dp_bits
// Range [14, 60] ensures:
// - Minimum 8: allows fast precompute table generation for small ranges
// - Maximum 60: leaves 4 bits margin in 64-bit limb for safety
// NOTE: For solving, DP >= 14 is recommended; for precompute table generation, DP >= 8 is allowed
#define MIN_DP_BITS			8
#define MAX_DP_BITS			60
// MAX_DP_CNT is now computed dynamically in GpuKang.cpp based on KangCnt and DP bits
// Old fixed value: (256 * 1024) caused overflow for old GPUs with DP < 20
// Formula: expected_dps = 2 * KangCnt * STEP_CNT / 2^DP * safety_factor
// For old GPU (KangCnt=2.2M, DP=14): 2*2228224*1000/16384*2 = 545K DPs expected
#define MAX_DP_CNT_DEFAULT		(512 * 1024)  // Fallback default
#define MAX_DP_CNT_SAFETY_FACTOR	2.5          // Safety margin for variance

#define JMP_MASK			(JMP_CNT-1)

#define DPTABLE_MAX_CNT		64

// MAX_CNT_LIST: CPU-side DP accumulation list size
// Increased to 16M to support low DP values with old GPU mode (2.2M kangaroos)
// Example: DP=14 produces ~270K DPs/step, DP=16 produces ~68K DPs/step
// Buffer must accommodate multiple kernel iterations while CheckNewPoints processes
#define MAX_CNT_LIST		(16 * 1024 * 1024)

#define DP_FLAG				0x8000
#define INV_FLAG			0x4000
#define JMP2_FLAG			0x2000
#define MINUS_FLAG			0x1000

#define MD_LEN				10

// DB record layout (host-side DP database)
#define DBREC_X_BYTES			32
#define DBREC_D_BYTES			24
#define DBREC_TYPE_BYTES		1
#define DBREC_PREFIX_BYTES		3
#define DB_REC_LEN			(DBREC_X_BYTES - DBREC_PREFIX_BYTES + DBREC_D_BYTES + DBREC_TYPE_BYTES)
#define DB_FIND_LEN			(DBREC_X_BYTES - DBREC_PREFIX_BYTES)

//#define DEBUG_MODE

// Precompute module verbose output (comment out for production builds)
//#define PRECOMPUTE_VERBOSE

//gpu kernel parameters
struct TKparams
{
	u64* Kangs;
	u32 KangCnt;
	u32 BlockCnt;
	u32 BlockSize;
	u32 GroupCnt;
	u64* L2;
	u64 DP;
	u32* DPs_out;
	u32 MaxDPCnt;  // Dynamic MAX_DP_CNT based on KangCnt and DP bits
	u64* Jumps1; //x(32b), y(32b), d(32b)
	u64* Jumps2; //x(32b), y(32b), d(32b)
	u64* Jumps3; //x(32b), y(32b), d(32b)
	u64* JumpsList; //list of all performed jumps, grouped by warp(32) every 8 groups (from PNT_GROUP_CNT). Each jump is 2 bytes: 10bit jump index + flags: INV_FLAG, DP_FLAG, JMP2_FLAG
	u32* DPTable;
	u32* L1S2;
	u64* LastPnts;
	u64* LoopTable;
	u32* dbg_buf;
	u32* LoopedKangs;
	bool IsGenMode; //tames generation mode
	bool IsBernsteinLangeMode; // Bernstein-Lange mode: all kangaroos start from Target
	bool SotaPlusMode; // SOTA+ mode: use cheap P-Q point in addition to P+Q

	u32 KernelA_LDS_Size;
	u32 KernelB_LDS_Size;
	u32 KernelC_LDS_Size;
};


//==============================================================================
// Precompute Table Definitions (Bernstein-Lange Algorithm)
//==============================================================================

// Precompute table algorithm parameters (based on walk1.cpp)
// R: r-adding walk step count (must be power of 2)
// W: distinguished point mask (must be power of 2)
// T: final table size
// N: candidate point count for precomputation
#define PTABLE_R_DEFAULT       128      // Default r-adding steps
#define PTABLE_W_DEFAULT       524288   // Default DP mask (2^19)
#define PTABLE_ALPHA           0.786    // Alpha parameter (optimal)
// Table generation kernel configuration (must match host launch config)
#define PTABLE_BATCH_SIZE      32       // Points per thread (batch inversion)
#define PTABLE_BLOCK_SIZE      256      // Threads per block for TableGenKernel (enables 2 CTAs/SM when shared=32KB)

// Precompute table entry (80 bytes per entry)
// Stores distinguished point x-coordinate, discrete log, and weight
// Requirements: 3.2 - Store full 256-bit x-coordinate for reliable matching
// Requirements: 3.3 - Compare all stored bits for collision detection
#pragma pack(push, 1)
struct PTableEntry {
    u64 x[4];           // Distinguished point x-coordinate (256-bit, FULL storage)
                        // x[0] = low 64 bits, x[3] = high 64 bits
                        // IMPORTANT: All 4 limbs must be stored for reliable collision detection
                        // Previous versions truncated to 128 bits which caused false matches
    u64 log[4];         // Discrete logarithm value (256-bit)
                        // log[0] = low 64 bits, log[3] = high 64 bits
    u64 weight;         // Weight for selection (collision count + steps)
    u32 collision_cnt;  // Number of collisions detected
    u32 padding;        // Bit 0: y_sign metadata (for point compression); rest reserved
};
#pragma pack(pop)

// Verify PTableEntry size at compile time
// Size: x[4](32) + log[4](32) + weight(8) + collision_cnt(4) + padding(4) = 80 bytes
static_assert(sizeof(PTableEntry) == 80, "PTableEntry must be exactly 80 bytes");","type":"text"}]

