	u64* d_tableonly_state_y;
	u64* d_tableonly_state_d;
	u64* d_tableonly_state_prefix;
	u64* d_tableonly_state_steps;
	u64* d_tableonly_state_rng;
	u32* d_tableonly_state_l1s2;

		// Precompute table support (Bernstein-Lange algorithm)
		// NOTE: Device representation depends on loaded_table_compression:
		// - COMPRESSION_NONE / COMPRESSION_POINT: d_precompute_table (PTableEntry, 80B/entry)
		// - COMPRESSION_HASH: d_precompute_table_hash (HashedPTableEntry, 24B/entry)
		// - COMPRESSION_SEED: d_precompute_table_seed (SeedPTableEntry, 40B/entry)
		// - COMPRESSION_HASHBITS: hashbits index + logs (variable-size payload)
		PTableEntry* d_precompute_table;          // Device array of precomputed entries (x-sorted)
		HashedPTableEntry* d_precompute_table_hash; // Device array of hashed entries (hash-sorted)
			SeedPTableEntry* d_precompute_table_seed;   // Device array of seed entries (x-sorted)
			// Paper Section 5 hashbits payload (COMPRESSION_HASHBITS)
			u64* d_precompute_table_hashbits_bitvec;       // bitvector words
			u32* d_precompute_table_hashbits_rank;         // rank prefix
			u32* d_precompute_table_hashbits_bucket_offsets; // bucket offsets (size=bucket_count+1)
			u64* d_precompute_table_hashbits_logs;         // 256-bit logs (log_count * 4 u64)
			u32 precompute_hashbits_hash_bits;
			u32 precompute_hashbits_rank_stride_words;
			u64 precompute_hashbits_bitvec_word_count;
			u64 precompute_hashbits_rank_count;
			u64 precompute_hashbits_bucket_count;
			u64 precompute_hashbits_log_count;
			u32 precompute_table_size;        // T (number of entries in table)
			u64 precompute_table_size_total;  // Global T_total used for paper DP coupling (may exceed u32)
			bool precompute_table_is_manifest; // Loaded from a PTAM manifest (multi-chunk)
			u32 precompute_table_active_chunk; // Active chunk index (manifest mode)
			std::vector<std::string> precompute_table_chunk_files;
			std::vector<u64> precompute_table_chunk_sizes;
			// PTAM v2 index (optional): per-chunk fence keys to avoid linear chunk scans.
			// Layout: chunk_key_max[i*4 + limb], where limb 0..3 matches the u64[4] representation used by queries.
			// For hash-compressed tables, only limb 3 is used (hash in key_max[3], others are 0).
			bool precompute_table_manifest_indexed;
			std::vector<u64> precompute_table_chunk_key_max;
			// Seed-proxy support for repacked (mixed-pool) seed tables:
			// PTAM v3 stores an array of per-pool start seeds. Each seed entry then carries pool_id.
			std::vector<u64> precompute_table_seed_pool_seeds;
			bool precompute_table_ready;      // Table generation complete flag
			bool precompute_table_enabled;    // Enable Bernstein-Lange mode for this solve (may be true even if table is only loaded on GPU 0)

	// Loaded table parameters for runtime validation
	// Requirements: 8.2, 8.3, 8.4 - Validate header parameters against runtime configuration
	u32 loaded_table_R;               // R value from loaded table (must match JMP_CNT)
	u64 loaded_table_W;               // W value from loaded table (must match 2^dp_bits)
	u32 loaded_table_range_bits;      // Range bits from loaded table
	u32 loaded_table_dp_bits;         // DP bits from loaded table
	u64 loaded_table_random_seed;     // Random seed from loaded table (Requirements: 2.4, 5.3)
	                                  // For version 2 tables, this is assumed to be 0

	// Version 4 parameters for Bernstein-Lange algorithm
	u8 loaded_table_start_offset[32]; // Start offset from loaded table (256-bit)
	CompressionType loaded_table_compression; // Compression type from loaded table
	u8 loaded_table_walk_mode;        // Walk mode from header.reserved[0] (PTableWalkMode)
	u32 loaded_table_start_pool_size; // Start pool size from header.reserved[1..4] (seed compression)

	/**
	 * @brief Query precompute table for distinguished point
	 * @param query_x Query x-coordinate (4 x u64, 256-bit)
