	 */
	void BatchQueryPrecomputeTable(
		const u64* d_query_x,
		u32 batch_size,
		u32* d_result_found,
		u64* d_result_log);

	/**
	 * @brief Query DPs against precompute table (host memory interface)
	 * 
	 * This is the main interface for CheckNewPoints to query DPs against the
	 * precompute table. It handles:
	 * 1. Allocating device memory for query data
	 * 2. Copying host data to device
	 * 3. Launching GPU batch query kernel
	 * 4. Copying results back to host
	 * 5. Freeing device memory
	 * 
	 * Requirements: 7.1, 7.3 - GPU batch query for collision detection
	 * 
	 * @param h_query_x Host array of query x-coordinates (batch_size x 4 x u64)
	 * @param batch_size Number of queries
	 * @param h_result_found Host array for results (batch_size x u32, 1=found, 0=not found)
	 * @param h_result_log Host array for result logs (batch_size x 4 x u64)
	 */
	void QueryDPsAgainstTable(
		const u64* h_query_x,
		u32 batch_size,
		u32* h_result_found,
		u64* h_result_log);

	// Hashbits helper: copy a range of logs from device to host (start/count in log records).
	// Used to enumerate collision buckets for COMPRESSION_HASHBITS without false negatives.
	bool CopyHashbitsLogsToHost(u32 start, u32 count, u64* h_out_logs);","type":"text"}]

