// Simple test for GpuKang precompute table functionality
#include <iostream>
#include <cstdio>
#include <cuda_runtime.h>
#include "Ec.h"
#include "GpuKang.h"

int main() {
    printf("=== GpuKang Precompute Table Test ===\n\n");

    // Check CUDA availability
    int device_count = 0;
    cudaError_t err = cudaGetDeviceCount(&device_count);
    if (err != cudaSuccess || device_count == 0) {
        printf("ERROR: No CUDA devices available!\n");
        return 1;
    }

    printf("Found %d CUDA device(s)\n", device_count);

    // Get device properties
    cudaDeviceProp prop;
    cudaGetDeviceProperties(&prop, 0);
    printf("Using GPU 0: %s\n", prop.name);
    printf("Compute Capability: %d.%d\n", prop.major, prop.minor);
    printf("Global Memory: %.2f GB\n\n", prop.totalGlobalMem / (1024.0 * 1024.0 * 1024.0));

    // Create RCGpuKang instance
    RCGpuKang gpu;
    gpu.CudaIndex = 0;
    gpu.mpCnt = 1;  // 1 SM for testing
    gpu.IsOldGpu = false;

    // Get L2 cache size
    cudaDeviceGetAttribute(&gpu.persistingL2CacheMaxSize,
                           cudaDevAttrMaxPersistingL2CacheSize, 0);

    printf("L2 Cache Size: %d bytes\n\n", gpu.persistingL2CacheMaxSize);

    // Test parameters (small values for quick testing)
    u32 N = 1024;      // Small candidate pool
    u32 T = 256;       // Small table size
    u32 R = 128;       // Standard jump count
    u32 W = 524288;    // Standard walk length (2^19)

    printf("Test Parameters:\n");
    printf("  N (candidates): %u\n", N);
    printf("  T (table size): %u\n", T);
    printf("  R (jumps): %u\n", R);
    printf("  W (walk length): %u (2^%d)\n\n", W, __builtin_ctz(W));

    // TEST 1: Generate Precompute Table
    printf("TEST 1: Generate Precompute Table\n");
    printf("---------------------------------------\n");

    bool success = gpu.GeneratePrecomputeTable(N, T, R, W);

    if (success) {
        printf("✓ PASS: Table generation succeeded\n");
        printf("  Table size: %u entries\n", gpu.precompute_table_size);
        printf("  Table ready: %s\n", gpu.precompute_table_ready ? "true" : "false");
    } else {
        printf("✗ FAIL: Table generation failed\n");
        return 1;
    }
    printf("\n");

    // TEST 2: Query Test (with placeholder data)
    printf("TEST 2: Query Test\n");
    printf("---------------------------------------\n");

    u64 query_x[4] = {
        0x123456789ABCDEF0ULL,
        0xFEDCBA9876543210ULL,
        0x0F0F0F0F0F0F0F0FULL,
        0xF0F0F0F0F0F0F0F0ULL
    };

    u64 result_log[4] = {0};
    bool found = gpu.QueryPrecomputeTable(query_x, result_log);

    printf("Query x-coordinate: %016llx %016llx %016llx %016llx\n",
           query_x[3], query_x[2], query_x[1], query_x[0]);

    if (found) {
        printf("✓ Entry found in table\n");
        printf("  Discrete log: %016llx %016llx %016llx %016llx\n",
               result_log[3], result_log[2], result_log[1], result_log[0]);
    } else {
        printf("○ Entry not found (expected - random query)\n");
    }
    printf("\n");

    // TEST 3: Memory Usage
    printf("TEST 3: Memory Usage\n");
    printf("---------------------------------------\n");

    size_t free_mem, total_mem;
    cudaMemGetInfo(&free_mem, &total_mem);
    size_t used_mem = total_mem - free_mem;

    printf("GPU Memory:\n");
    printf("  Total: %.2f MB\n", total_mem / (1024.0 * 1024.0));
    printf("  Used: %.2f MB\n", used_mem / (1024.0 * 1024.0));
    printf("  Free: %.2f MB\n", free_mem / (1024.0 * 1024.0));
    printf("  Table size: %.2f MB (%u entries)\n",
           (T * sizeof(PTableEntry)) / (1024.0 * 1024.0), T);
    printf("\n");

    // TEST 4: Cleanup
    printf("TEST 4: Cleanup Test\n");
    printf("---------------------------------------\n");

    gpu.ReleasePrecomputeTable();

    if (!gpu.precompute_table_ready && gpu.precompute_table_size == 0) {
        printf("✓ PASS: Table released successfully\n");
    } else {
        printf("✗ FAIL: Table not properly released\n");
    }
    printf("\n");

    printf("=== All Tests Completed ===\n");
    printf("\n");
    printf("Summary:\n");
    printf("  • Table generation: %s\n", success ? "✓ PASS" : "✗ FAIL");
    printf("  • Memory management: ✓ PASS\n");
    printf("  • Cleanup: ✓ PASS\n");

    return 0;
}","type":"text"}]

