#pragma once

#include <string>
#include <cstdint>
#include <memory>
#include "../common/shard_config.h"
#include "../common/machine_fingerprint.h"

namespace lottery {

struct AttemptInfo {
    int64_t attempt_id;
    uint64_t shard_id;
    std::string range_start;
    std::string range_end;
    int64_t started_at;
    uint64_t operations;
    uint64_t dp_count;
    double speed_gks;
    std::string status;
    int attempt_number;  // How many times this shard was attempted
};

class LotteryClient {
public:
    LotteryClient(const std::string& server_url = "");
    ~LotteryClient();

    // Connection
    bool connect();
    bool isConnected() const;
    std::string getNodeId() const;
    std::string getMachineId() const;

    // Machine registration (server-managed mode)
    bool registerMachine(const MachineInfo& info);
    bool allocateShard(AttemptInfo& info);  // Server decides shard

    // Shard operations
    bool getRandomShard(AttemptInfo& info);
    bool startShard(uint64_t shard_id, AttemptInfo& info);
    bool updateProgress(int64_t attempt_id, uint64_t ops, uint64_t dps, double speed);
    bool completeShard(int64_t attempt_id, const std::string& status,
                       const std::string& private_key = "");

    // Heartbeat (server mode only)
    bool sendHeartbeat(int64_t assignment_id, uint64_t ops, uint64_t dps, double speed);

    // Statistics
    bool getStats(uint64_t& total_attempts, uint64_t& unique_shards,
                  double& coverage_percent);

    // Local-only mode (no server, SQLite only)
    bool initLocalMode(const std::string& db_path);
    bool isLocalMode() const;
    bool isServerMode() const;

    // GPU info for reporting
    void setGpuInfo(const std::string& info);

private:
    class Impl;
    std::unique_ptr<Impl> impl_;
};

// Global lottery mode interface for RCKangaroo integration
bool InitLotteryMode(const char* server_url, const char* local_db);
bool GetLotteryRange(std::string& range_start, std::string& range_end);
bool RequestNextShard(std::string& range_start, std::string& range_end);  // Get next shard after completion
void UpdateLotteryProgress(uint64_t ops, uint64_t dps, double speed);
void CompleteLotteryShard(bool found, const char* private_key);
bool SendHeartbeat(uint64_t ops, uint64_t dps, double speed);  // Send heartbeat to server
bool IsLotteryMode();
bool IsServerMode();  // Check if running in server mode (continuous allocation)
int64_t GetCurrentAttemptId();
uint64_t GetCurrentShardId();
const char* GetMachineId();

}  // namespace lottery","type":"text"}]

