namespace lottery {

// Puzzle #135 Configuration
static const char* PUZZLE_135_PUBKEY =
    "02145d2611c823a396ef6712ce0f712f09b9b4f3135e3e0aa3230fb9b6d08d1e16";

// Correct shard config: ~10 minutes per shard on RTX 4090
// Total range: 2^134, Shard size: 2^84, Total shards: 2^50
static const uint64_t DEFAULT_TOTAL_SHARDS = 1ULL << 50;  // ~1.1 quadrillion
static const uint32_t DEFAULT_SHARD_BITS = 50;
static const uint32_t DEFAULT_SHARD_SIZE_BITS = 84;   // 134 - 50

struct ShardConfig {
    uint64_t total_shards;
    uint32_t shard_bits;
    uint32_t shard_size_bits;
    // For 135-bit values, use (low64, mid64, high8) representation
    // value = high << 128 + mid << 64 + low
    uint64_t range_start_low;   // bits 0-63
    uint64_t range_start_mid;   // bits 64-127
    uint8_t range_start_high;   // bits 128-134
    uint64_t range_end_low;
    uint64_t range_end_mid;
    uint8_t range_end_high;
};

inline ShardConfig GetDefaultConfig() {
    ShardConfig cfg;
    cfg.total_shards = DEFAULT_TOTAL_SHARDS;
    cfg.shard_bits = DEFAULT_SHARD_BITS;
    cfg.shard_size_bits = DEFAULT_SHARD_SIZE_BITS;
    // 2^134 = 0x4000000000000000000000000000000000 (135 bits)
    // In (low, mid, high) format: value = high << 128 + mid << 64 + low
    // 2^134 = 2^(128+6) = 64 * 2^128, so high = 64 = 0x40, mid = 0, low = 0
    cfg.range_start_low = 0x0000000000000000ULL;
    cfg.range_start_mid = 0x0000000000000000ULL;
    cfg.range_start_high = 0x40;  // 2^6 = 64
    // 2^135-1 = 0x7fffffffffffffffffffffffffffffffff
    // All 135 bits set: high = 0x7F (7 bits), mid = all 1s, low = all 1s
    cfg.range_end_low = 0xFFFFFFFFFFFFFFFFULL;
    cfg.range_end_mid = 0xFFFFFFFFFFFFFFFFULL;
    cfg.range_end_high = 0x7F;  // 2^7 - 1 = 127
    return cfg;
}

// Generate random shard ID using system entropy (64-bit for 2^50 shards)
inline uint64_t GetRandomShardId(uint64_t total_shards) {
    uint64_t rand_val;
#ifdef _WIN32
    uint32_t hi, lo;
    rand_s(&hi);
    rand_s(&lo);
    rand_val = ((uint64_t)hi << 32) | lo;
#else
    FILE* f = fopen("/dev/urandom", "rb");
    if (f) {
        size_t ret = fread(&rand_val, sizeof(rand_val), 1, f);
        fclose(f);
        if (ret != 1) rand_val = (uint64_t)time(nullptr);
    } else {
        rand_val = (uint64_t)time(nullptr);
    }
#endif
    return rand_val % total_shards;
}","type":"text"}]

