    char buffer[ size +1 ]; // +1 for NUL termination byte 

    std::cerr <<"\n" "Calling std::snprintf(buffer,size,...)"<< std::endl;
    size = std::snprintf( buffer, size+1, "This is the string [%s] and this is the integer [%d]", "blablabla", 12345 );
