extern u32 gTotalErrors;

//executes in separate thread
void RCGpuKang::Execute()
{
	cudaSetDevice(CudaIndex);

	if (!Start())
	{
		gTotalErrors++;
		return;
	}
#ifdef DEBUG_MODE
	u64 iter = 1;
#endif
	cudaError_t err;	
	int buf_idx = 0;
	bool in_flight[2] = { false, false };
	int host_cnt[2] = { 0, 0 };
	size_t host_bytes = (size_t)MAX_DP_CNT * GPU_DP_SIZE;
	u64 pnt_cnt = (u64)KangCnt * STEP_CNT;
	while (!StopFlag)
	{
		int cur = buf_idx;
		int prev = cur ^ 1;

		if (in_flight[prev])
		{
			err = cudaStreamSynchronize(Streams[prev]);
			if (err != cudaSuccess)
			{
				printf("GPU %d, CallGpuKernel failed: %s\r\n", CudaIndex, cudaGetErrorString(err));
				gTotalErrors++;
				break;
			}

			int cnt = host_cnt[prev];
			if (cnt >= MAX_DP_CNT)
			{
				cnt = MAX_DP_CNT;
				printf("GPU %d, gpu DP buffer overflow, some points lost, increase DP value!\r\n", CudaIndex);
			}
			if (cnt)
				AddPointsToList(DPs_outHost[prev], cnt, pnt_cnt);

#ifdef DEBUG_MODE
			cudaMemcpy(dbg, Kparams.dbg_buf, 1024, cudaMemcpyDeviceToHost);
			u32 lcnt;
			cudaMemcpy(&lcnt, Kparams.LoopedKangs, 4, cudaMemcpyDeviceToHost);
			//printf("GPU %d, Looped: %d\r\n", CudaIndex, lcnt);
#endif

			float elapsed_ms = 0.0f;
			cudaEventElapsedTime(&elapsed_ms, DpStart[prev], DpEnd[prev]);
			u64 tm = (elapsed_ms < 1.0f) ? 1 : (u64)elapsed_ms;
			int cur_speed = (int)(pnt_cnt / (tm * 1000));
			SpeedStats[cur_stats_ind] = cur_speed;
			cur_stats_ind = (cur_stats_ind + 1) % STATS_WND_SIZE;
			in_flight[prev] = false;
		}

		Kparams.DPs_out = DPs_outDev[cur];
		cudaMemsetAsync(Kparams.DPs_out, 0, 4, Streams[cur]);
		cudaMemsetAsync(Kparams.DPTable, 0, KangCnt * sizeof(u32), Streams[cur]);
		cudaMemsetAsync(Kparams.LoopedKangs, 0, 8, Streams[cur]);
		cudaEventRecord(DpStart[cur], Streams[cur]);
		CallGpuKernelABC(Kparams, Streams[cur]);
		cudaMemcpyAsync(&host_cnt[cur], Kparams.DPs_out, 4, cudaMemcpyDeviceToHost, Streams[cur]);
		cudaMemcpyAsync(DPs_outHost[cur], Kparams.DPs_out + 4, host_bytes, cudaMemcpyDeviceToHost, Streams[cur]);
		cudaEventRecord(DpEnd[cur], Streams[cur]);
		in_flight[cur] = true;
		buf_idx ^= 1;

#ifdef DEBUG_MODE
		if ((iter % 300) == 0)
		{
			int corr_cnt = Dbg_CheckKangs();
			if (corr_cnt)
			{
				printf("DBG: GPU %d, KANGS CORRUPTED: %d\r\n", CudaIndex, corr_cnt);
				gTotalErrors++;
			}
			else
				printf("DBG: GPU %d, ALL KANGS OK!\r\n", CudaIndex);
		}
		iter++;
#endif
	}

	for (int i = 0; i < 2; i++)
	{
		if (!in_flight[i])
			continue;
		err = cudaStreamSynchronize(Streams[i]);
		if (err != cudaSuccess)
		{
			gTotalErrors++;
			break;
		}
		int cnt = host_cnt[i];
		if (cnt >= MAX_DP_CNT)
			cnt = MAX_DP_CNT;
		if (cnt)
			AddPointsToList(DPs_outHost[i], cnt, pnt_cnt);
	}

	Release();
}

